- name: Create Consul service definition for SeaweedFS filer
  copy:
    content: |
      {
        "service": {
          "name": "seaweedfs-filer",
          "port": {{ seaweedfs.filer_port }},
          "tags": ["seaweedfs", "filer", "storage"],
          "check": {
            "http": "http://localhost:{{ seaweedfs.filer_port }}/",
            "interval": "10s",
            "timeout": "5s"
          }
        }
      }
    dest: /etc/consul.d/seaweedfs-filer.json
    owner: root
    group: root
    mode: '0644'
